(async()=>{
 try{
  var app=document.getElementById("app");
  var ss=(app.__vnode||app._vnode).component.setupState;
  var dbg=window.__psDebug;
  var out={ver:window.APP_VERSION,hasSS:!!ss,hasDbg:!!dbg};
  if(!ss||!dbg)return out;
  var sleep=function(ms){return new Promise(function(r){setTimeout(r,ms);});};
  async function maxLoading(ms){var hit=false,t=Date.now();while(Date.now()-t<ms){if(dbg.moduleLoading)hit=true;await sleep(8);}return hit;}
  out.preloadKeys=dbg.keys().slice().sort();
  // (b) Lanchas fria vs instantanea
  Object.keys(dbg.moduleCache).forEach(function(k){delete dbg.moduleCache[k];});
  ss.goModule("dashboard");await sleep(400);
  ss.goModule("lanchas");
  out.lanchasV1_loadingSeen=await maxLoading(400);
  await sleep(1200);
  out.keysAfterLanchasV1=dbg.keys();
  ss.goModule("dashboard");await sleep(500);
  ss.goModule("lanchas");
  out.lanchasV2_loadingSeen=await maxLoading(400);
  out.lanchasV2_moduleLoadingNow=dbg.moduleLoading;
  // (a) Finanzas (pesado, con await) fria vs instantanea -> termina en Finanzas V2 para el screenshot
  Object.keys(dbg.moduleCache).forEach(function(k){delete dbg.moduleCache[k];});
  ss.goModule("dashboard");await sleep(400);
  ss.goModule("finanzas");
  out.finanzasV1_loadingSeen=await maxLoading(600);
  await sleep(1500);
  out.keysAfterFinanzasV1=dbg.keys();
  ss.goModule("dashboard");await sleep(500);
  ss.goModule("finanzas");
  out.finanzasV2_loadingSeen=await maxLoading(500);
  out.finanzasV2_moduleLoadingNow=dbg.moduleLoading;
  out.finalKeys=dbg.keys().slice().sort();
  out.currentModule=ss.currentModule;
  out.overflowX=document.documentElement.scrollWidth-window.innerWidth;
  return out;
 }catch(e){return{crash:e.message,stack:(e.stack||"").slice(0,300)};}
})()
